9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survivesOrIsBorn = (neighborCount: number, isAlive: boolean): boolean =>
12	  neighborCount === 3 || (neighborCount === 2 && isAlive);
13	
14	const countLiveNeighborsByCell = (liveCells: Array<Cell>): Map<string, { cell: Cell; count: number }> => {
15	  const tallies = new Map<string, { cell: Cell; count: number }>();
16	  for (const [x, y] of liveCells) {
17	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
18	      const neighbor: Cell = [x + dx, y + dy];
19	      const k = cellKey(neighbor);
20	      const existing = tallies.get(k);
21	      if (existing) existing.count++;
22	      else tallies.set(k, { cell: neighbor, count: 1 });
23	    }
24	  }
25	  return tallies;
26	};
27	
28	export function nextGeneration(liveCells: Array<Cell>): Array<Cell> {
29	  const liveSet = new Set<string>(liveCells.map(cellKey));
30	  const neighborTallies = countLiveNeighborsByCell(liveCells);
31	
32	  const result: Array<Cell> = [];
33	  for (const [k, { cell, count }] of neighborTallies) {
34	    if (survivesOrIsBorn(count, liveSet.has(k))) result.push(cell);
35	  }
36	  return result;
37	}
