      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor);
      const existing = tallies.get(k);
      if (existing) existing.count++;
      else tallies.set(k, { cell: neighbor, count: 1 });
    }
  }
  return tallies;
};

export function nextGeneration(liveCells: Array<Cell>): Array<Cell> {
  const liveSet = new Set<string>(liveCells.map(cellKey));
  const neighborTallies = countLiveNeighborsByCell(liveCells);

